using System.Net;

var builder = WebApplication.CreateBuilder(args);

// Breaking change 4 вЂ” ValidateOnBuild/ValidateScopes enabled in development.
// A singleton capturing a scoped service (captive dependency) now throws at startup.
// Fix: register CacheService as scoped so it doesn't outlive the scoped IUserService.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// Breaking change 1 вЂ” HttpClientFactory now uses SocketsHttpHandler by default.
// Casting PrimaryHandler to HttpClientHandler throws InvalidCastException.
// Fix: use ConfigurePrimaryHttpMessageHandler to set the handler type explicitly.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// Breaking change 2 вЂ” Trace-level HttpClient logs now redact all header values.
// Fix: allowlist specific non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id"
        && h != "X-Correlation-Id"
        && h != "Cache-Control"
        && h != "Accept"
        && h != "Content-Type"));

// Breaking change 3 вЂ” ForwardedHeaders middleware ignores X-Forwarded-* from unknown proxies.
// Fix: register your trusted proxy address(es) in KnownProxies.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: replace with your actual reverse-proxy IP address(es)
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

